// src/pages/bank/TransferPage.jsx
import { useState }  from "react";
import { useToast }  from "../../context/ToastContext";
import PageHeader    from "../../components/shared/PageHeader";
import DataTable     from "../../components/shared/DataTable";
import { donations } from "../../data/mockData";
import { tokenApi }  from "../../services/api";

const fmt = (n) => n?.toLocaleString() ?? "–";

export default function TransferPage() {
  const toast = useToast();
  const EMPTY = { userCert: "", tokenId: "", toId: "" };
  const [form, setForm] = useState(EMPTY);
  const [loading, setLoading] = useState(false);
  const upd = (k) => (e) => setForm((p) => ({ ...p, [k]: e.target.value }));

  const handleSubmit = async () => {
    if (!form.userCert || !form.tokenId || !form.toId) {
      toast("UserCert, token ID and receiver ID are required", "error");
      return;
    }

    setLoading(true);
    try {
      await tokenApi.transfer(form);
      toast("Transfer submitted to ledger", "success");
      setForm((prev) => ({ ...EMPTY, userCert: prev.userCert }));
    } catch (err) {
      toast(err?.response?.data?.error || err.message || "Transfer failed", "error");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div>
      <PageHeader title="Transfer Tokens" desc="Move tokens between wallets on the ledger" />
      <div className="grid-2">
        <div className="card">
          <div className="form-grid section-gap">
            <div className="form-group"><label>User Cert</label><input value={form.userCert} onChange={upd("userCert")} placeholder="User certificate ID" /></div>
            <div className="form-group"><label>Token ID</label><input value={form.tokenId} onChange={upd("tokenId")} placeholder="e.g. token001" /></div>
            <div className="form-group"><label>To ID</label><input value={form.toId} onChange={upd("toId")} placeholder="e.g. NGO001" /></div>
            <div className="form-actions">
              <button className="btn btn-secondary" onClick={() => setForm((prev) => ({ ...EMPTY, userCert: prev.userCert }))}>Clear</button>
              <button className="btn btn-primary" onClick={handleSubmit} disabled={loading}>{loading ? "Submitting..." : "Submit Transfer ⇄"}</button>
            </div>
          </div>
        </div>

        <div className="card">
          <div className="card-title" style={{ marginBottom:14 }}>Recent Transfers</div>
          <DataTable
            columns={[
              { key:"id",     label:"ID",     mono:true },
              { key:"donor",  label:"From"   },
              { key:"fund",   label:"To Fund" },
              { key:"amount", label:"Amount", render:(r) => <span className="text-gold">{fmt(r.amount)}</span> },
              { key:"date",   label:"Date",   mono:true },
            ]}
            data={donations.slice(0, 2)}
          />
        </div>
      </div>
    </div>
  );
}
